var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0030-05: <color=#ffd34c>샤오린</color>      ","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS002M0030-05：<color=#ffd34c>シャオリン</color>      ","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0030-05: <color=#ffd34c>曉琳</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS002M0030-05: <color=#ffd34c>เสี่ยวหลิน</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số AS002M0030-05: <color=#ffd34c>Xiao Lin</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>      \\nCCN No. AS002M0030-05: <color=#ffd34c>小琳</color>      ","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS002M0030-05: <color=#ffd34c>Xiao Lin</color>      ","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS002M0030-05\xA0: <color=#ffd34c>Xiao Lin</color>      "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"알트 소대?","JPN":"アルト小隊？","ENG":"The ALT Squad?","TWN":"阿爾特小隊？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"술맛 떨어지게시리...... 그것들이랑 엮이는 바람에 우린 실직자 신세라고.","JPN":"酒が不味くなるだろうが……そいつらと関わったせいで、俺たちゃ職無しになっちまったんだぞ。","ENG":"I don't even want to talk about them... We all lost our jobs because we got involved with them.","TWN":"酒都變難喝了……就因為和他們有瓜葛，我們都變成了失業者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"젠장. 어디서 금칠한 얘기만 듣고 온 모양인데, 형씨.","JPN":"ちっくしょう。兄ちゃんよォ、どうせどっかで景気のいい話でも聞いてきたんだろ？","ENG":"Dammit. I don't know what kind of sugar-coated rumors you've heard, man.","TWN":"該死，真是在哪都不缺說書的人啊，老兄。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 내가 이 바닥에서 일하면서 그런 독종들을 못 봤어.","JPN":"俺もこの業界は長いが、あんな野暮ったい連中にはお目にかかった試しがねえ。","ENG":"But I've never seen anyone who are more determined than they are while working here.","TWN":" 啊，我在這裡圈子裡混了這麼久，從來沒有看過這麼難纏的傢伙。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래, 독종! 아주 독종 중에 상독종들이지!","JPN":"ああ、そうさ！野暮ったいどころの話じゃねえ！","ENG":"Yes, determined! So determined, that you get sick of them!","TWN":"對啊，真難纏！沒人可以比得上啊！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"나는 가정이 있는 사람이란 말이야, 가정이.","JPN":"俺は妻子持ちだぞ。養う家族がいるってんだ。","ENG":"I have a family to feed you know... a family.","TWN":"我是個有家庭的人啊，家庭。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 이터니움 부스러기 좀 챙겨 간다니까 콩알만 한 계집애들이 눈을 시퍼렇게 뜨고 말이야.","JPN":"だというのにだ。エタニウムの残りくずをちょいとばかし拝借しようとしたら、あの小娘ども……鬼みたいな形相で睨みやがった。","ENG":"But when I tried to take a tiny Eternium crumb, those little girls stared me down like I was some bum.","TWN":"不過，一聽到我要帶走一些永恆之金，那群小丫頭都瞪大眼睛看著我。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"빌어먹을...... 카운터 아닌 게 한이지.","JPN":"クソ……こちとらカウンターじゃねえからよ。文句の一つも言えやしねえ。","ENG":"Geez... It's my fault for not being a Counter.","TWN":"該死的……有時候真後悔自己不是個制裁者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"엉? 얘가 누군지 아냐고?","JPN":"あぁん？この娘が誰か知ってるかって？","ENG":"Huh? Do I know who this is?","TWN":"嗯？你知道這是誰嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"이 형씨 보게. 좀 어울려 주니까 아주 생으로 낼름......","JPN":"まったく虫のいい兄ちゃんだなぁ。これ以上タダでしゃべってやる義理なんざ……","ENG":"Look here. You think you can milk everything just because...","TWN":"看看你這老兄，都相處了這麼久了，架子還這麼大……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 술을 사면 산다고 얘기를 하지 그랬어.","JPN":"おっ、ここは兄ちゃんの奢りだって？それならそうと早く言えってんだ。","ENG":"Oh, you should have said that you were buying a drink first.","TWN":"啊，你要買酒就直接說啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래, 그래. 얘 이름이 그러니까...... 샤오린? 샤오린 맞지?","JPN":"えーと？　この娘の名前は確か……シャオリン？　シャオリンだろ？","ENG":"Yes, right. This kid is... Xiao Lin? Xiao Lin, isn't it?","TWN":"對對對，她的名字是……曉琳？曉琳對吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 이 녀석 아주 날렸지. 날렸어. 실력이 아주 귀신 같았거든.","JPN":"ああ、こいつは凄ぇ奴さ。凄ぇってもんじゃねぇ。神がかりってやつだぜ。","ENG":"Yeah, this girl really knows her stuff. She's a beast. Literally a monster.","TWN":"啊，那傢伙屌，真的很屌，實力強得跟鬼一樣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"키는 제일 째깐한 게, 총솜씨가 아주 귀신 들렸다니까.","JPN":"背丈は一番ちっこいのに、鬼のように射撃が上手えんだよな。","ENG":"She might be a shorty, but she's one hell of a marksman.","TWN":"雖然身高長得最矮，但槍法真的就跟鬼一樣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 녀석들이랑 같이 뛴 작전에서 제일 고비가 갑피를 두른 침식체였어.","JPN":"あの隊の連中との共同作戦で最も難敵だったのが、甲皮をまとった侵食体さ。","ENG":"During the operation I went on with them, we ran into an armored C.O.","TWN":"和那些傢伙一起行動時，最危險的就是遇到包覆著外殼的侵蝕體吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"애초에 그런 게 있다는 정보도 못 들었거니와, 언더그라운드에서 벌어먹고 사는 시궁창 인생들이 뭐 얼마나 대단한 무기를 준비하겠어?","JPN":"あんな野郎は情報になかったしよ、こちとらアンダーグラウンドで食い扶持稼ごうって底辺どもだからな。ろくな武器すら持ってねえ。","ENG":"We didn't hear nothing about that during the briefing, and people like us who make a living in the Underground don't have the weapons to deal with that.","TWN":"我們一開始也沒聽說過這種東西，況且在地下世界過著垃圾人生的人，又能準備多好的武器？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"기껏해야 제대로 날아갈지도 모를 RPG 정도지.","JPN":"せいぜい、ちゃんと弾が飛ぶかどうかわからねえRPGがいいところだな。","ENG":"At best, we might have a trash RPG to use.","TWN":"頂多就是個還不知道能不能發射的RPG。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};